import math

class Solution:
    def maxKelements(self, nums, k):
        arr = list(nums)
        score = 0
        for _ in range(k):
            best = 0
            for i in range(1, len(arr)):
                if arr[i] > arr[best]:
                    best = i
            score += arr[best]
            arr[best] = math.ceil(arr[best] / 3)
        return score

