var maxKelements = function(nums, k) {
    const heap = nums.slice();
    const n = heap.length;
    function siftDown(i, size) {
        while (true) {
            let largest = i;
            const l = 2 * i + 1, r = 2 * i + 2;
            if (l < size && heap[l] > heap[largest]) largest = l;
            if (r < size && heap[r] > heap[largest]) largest = r;
            if (largest === i) break;
            const tmp = heap[i]; heap[i] = heap[largest]; heap[largest] = tmp;
            i = largest;
        }
    }
    for (let i = Math.floor(n / 2) - 1; i >= 0; i--) siftDown(i, n);
    let score = 0;
    for (let t = 0; t < k; t++) {
        const top = heap[0];
        score += top;
        heap[0] = Math.ceil(top / 3);
        siftDown(0, n);
    }
    return score;
};
